  1→/**
  2→ * Assess Comment Parser
  3→ *
  4→ * Detects and parses /assess command output from GitHub issue comments.
  5→ * This is the unified parser that handles both the new /assess format
  6→ * and the legacy /solve format for backward compatibility.
  7→ *
  8→ * When an assess comment exists, its phase recommendations take precedence
  9→ * over content analysis (but not over labels).
 10→ *
 11→ * @example
 12→ * ```typescript
 13→ * import { findAssessComment, parseAssessWorkflow } from './assess-comment-parser';
 14→ *
 15→ * const comments = [
 16→ *   { body: "Some regular comment" },
 17→ *   { body: "## Assess Analysis\n\n→ PROCEED — Ready.\n\n<!-- assess:phases=spec,exec,qa -->" },
 18→ * ];
 19→ *
 20→ * const assessComment = findAssessComment(comments);
 21→ * if (assessComment) {
 22→ *   const workflow = parseAssessWorkflow(assessComment.body);
 23→ *   // workflow: { phases: ['spec', 'exec', 'qa'], action: 'PROCEED', ... }
 24→ * }
 25→ * ```
 26→ */
 27→
 28→import type { Phase } from "./workflow/types.js";
 29→import type { PhaseSignal } from "./phase-signal.js";
 30→
 31→/**
 32→ * The 6 fixed actions that /assess can recommend
 33→ */
 34→export type AssessAction =
 35→  | "PROCEED"
 36→  | "CLOSE"
 37→  | "MERGE"
 38→  | "REWRITE"
 39→  | "CLARIFY"
 40→  | "PARK";
 41→
 42→/**
 43→ * Result of parsing an assess comment (superset of SolveWorkflowResult)
 44→ */
 45→export interface AssessWorkflowResult {
 46→  /** Phases recommended by assess (only meaningful for PROCEED) */
 47→  phases: Phase[];
 48→  /** Whether quality loop is recommended */
 49→  qualityLoop: boolean;
 50→  /** The issue numbers mentioned in the assess comment */
 51→  issueNumbers: number[];
 52→  /** Raw workflow string (e.g., "spec → exec → qa") */
 53→  workflowString?: string;
 54→  /** The recommended action (one of the 6 fixed actions) */
 55→  action?: AssessAction;
 56→}
 57→
 58→/**
 59→ * Backward-compatible alias for AssessWorkflowResult
 60→ */
 61→export type SolveWorkflowResult = AssessWorkflowResult;
 62→
 63→/**
 64→ * Comment structure (simplified from GitHub API)
 65→ */
 66→export interface IssueComment {
 67→  body: string;
 68→  author?: {
 69→    login: string;
 70→  };
 71→  createdAt?: string;
 72→}
 73→
 74→/**
 75→ * Markers that indicate an assess comment (new format)
 76→ */
 77→const ASSESS_MARKERS = [
 78→  "## Assess Analysis",
 79→  "## Assess Workflow",
 80→  "*Generated by `/assess",
 81→];
 82→
 83→/**
 84→ * Markers that indicate a solve comment (legacy format)
 85→ */
 86→const SOLVE_MARKERS = [
 87→  "## Solve Analysis",
 88→  "## Solve Workflow for Issues:",
 89→  "## Solve Workflow for Issue:",
 90→  "### Recommended Workflow",
 91→  "*📝 Generated by `/solve",
 92→];
 93→
 94→/**
 95→ * All markers (both assess and solve)
 96→ */
 97→const ALL_MARKERS = [...ASSESS_MARKERS, ...SOLVE_MARKERS];
 98→
 99→/**
100→ * Pattern to extract phases from workflow string
101→ * Matches: `/spec`, `/exec`, `/test`, `/qa`, etc.
102→ * Also matches without slash: `spec`, `exec`, `test`, `qa` (for arrow notation)
103→ */
104→const PHASE_PATTERN =
105→  /\/?(?<!\w)(spec|exec|test|qa|security-review|testgen|loop)(?!\w)/g;
106→
107→/**
108→ * Pattern to detect quality loop recommendation
109→ */
110→const QUALITY_LOOP_PATTERNS = [
111→  /quality\s*loop.*auto-enable/i,
112→  /--quality-loop/i,
113→  /quality\s*loop.*recommended/i,
114→  /enable.*quality\s*loop/i,
115→];
116→
117→/**
118→ * Pattern to extract structured data from HTML comment markers
119→ * Matches both: <!-- assess:phases=exec,qa --> and <!-- solve:phases=exec,qa -->
120→ */
121→const HTML_MARKER_PATTERN =
122→  /<!--\s*(?:assess|solve):(\w[\w-]*)=([\w,.-]*)\s*-->/g;
123→
124→/**
125→ * Pattern to extract assess-specific HTML markers (takes precedence)
126→ */
127→const ASSESS_HTML_MARKER_PATTERN = /<!--\s*assess:(\w[\w-]*)=([\w,.-]*)\s*-->/g;
128→
129→/**
130→ * Pattern to extract issue numbers from header
131→ * Matches: "## Solve Workflow for Issues: 123, 456" or "#123"
132→ */
133→const ISSUE_NUMBER_PATTERN = /#?(\d+)/g;
134→
135→/**
136→ * Valid assess actions
137→ */
138→const VALID_ACTIONS: AssessAction[] = [
139→  "PROCEED",
140→  "CLOSE",
141→  "MERGE",
142→  "REWRITE",
143→  "CLARIFY",
144→  "PARK",
145→];
146→
147→/**
148→ * Structured data extracted from HTML comment markers
149→ */
150→export interface AssessMarkers {
151→  /** Recommended phases */
152→  phases?: string[];
153→  /** Whether to skip spec */
154→  skipSpec?: boolean;
155→  /** Whether browser testing is needed */
156→  browserTest?: boolean;
157→  /** Whether quality loop is recommended */
158→  qualityLoop?: boolean;
159→  /** The recommended action */
160→  action?: AssessAction;
161→}
162→
163→/**
164→ * Backward-compatible alias for AssessMarkers
165→ */
166→export type SolveMarkers = AssessMarkers;
167→
168→// ─── Detection Functions ────────────────────────────────────────────────────
169→
170→/**
171→ * Check if a comment is an assess command output (new format)
172→ */
173→export function isAssessComment(body: string): boolean {
174→  return ALL_MARKERS.some((marker) => body.includes(marker));
175→}
176→
177→/**
178→ * Check if a comment is a solve command output (legacy format)
179→ * @deprecated Use isAssessComment instead
180→ */
181→export function isSolveComment(body: string): boolean {
182→  return isAssessComment(body);
183→}
184→
185→/**
186→ * Find the most recent assess/solve comment from a list of comments
187→ */
188→export function findAssessComment(
189→  comments: IssueComment[],
190→): IssueComment | null {
191→  for (let i = comments.length - 1; i >= 0; i--) {
192→    if (isAssessComment(comments[i].body)) {
193→      return comments[i];
194→    }
195→  }
196→  return null;
197→}
198→
199→/**
200→ * Find the most recent solve comment from a list of comments
201→ * @deprecated Use findAssessComment instead
202→ */
203→export function findSolveComment(
204→  comments: IssueComment[],
205→): IssueComment | null {
206→  return findAssessComment(comments);
207→}
208→
209→// ─── Parsing Functions ──────────────────────────────────────────────────────
210→
211→/**
212→ * Parse phases from a workflow string
213→ */
214→function parseWorkflowString(workflowString: string): Phase[] {
215→  const phases: Phase[] = [];
216→  const matches = workflowString.matchAll(PHASE_PATTERN);
217→
218→  for (const match of matches) {
219→    const phase = match[1] as Phase;
220→    if (!phases.includes(phase)) {
221→      phases.push(phase);
222→    }
223→  }
224→
225→  return phases;
226→}
227→
228→/**
229→ * Parse HTML comment markers from a comment body
230→ *
231→ * Supports both `assess:` and `solve:` prefixes.
232→ * When both are present, `assess:` markers take precedence.
233→ */
234→export function parseAssessMarkers(body: string): AssessMarkers {
235→  const markers: AssessMarkers = {};
236→
237→  // First pass: collect all markers (both assess: and solve:)
238→  const allMatches = body.matchAll(HTML_MARKER_PATTERN);
239→  for (const match of allMatches) {
240→    applyMarker(markers, match[1], match[2]);
241→  }
242→
243→  // Second pass: assess: markers override solve: markers
244→  const assessMatches = body.matchAll(ASSESS_HTML_MARKER_PATTERN);
245→  for (const match of assessMatches) {
246→    applyMarker(markers, match[1], match[2]);
247→  }
248→
249→  return markers;
250→}
251→
252→/**
253→ * Apply a single marker key-value pair to the markers object
254→ */
255→function applyMarker(markers: AssessMarkers, key: string, value: string): void {
256→  switch (key) {
257→    case "phases":
258→      markers.phases = value.split(",").filter(Boolean);
259→      break;
260→    case "skip-spec":
261→      markers.skipSpec = value === "true";
262→      break;
263→    case "browser-test":
264→      markers.browserTest = value === "true";
265→      break;
266→    case "quality-loop":
267→      markers.qualityLoop = value === "true";
268→      break;
269→    case "action":
270→      if (VALID_ACTIONS.includes(value as AssessAction)) {
271→        markers.action = value as AssessAction;
272→      }
273→      break;
274→  }
275→}
276→
277→/**
278→ * Parse HTML comment markers (backward-compatible alias)
279→ * @deprecated Use parseAssessMarkers instead
280→ */
281→export function parseSolveMarkers(body: string): AssessMarkers {
282→  return parseAssessMarkers(body);
283→}
284→
285→/**
286→ * Parse an assess/solve comment to extract workflow information
287→ */
288→export function parseAssessWorkflow(body: string): AssessWorkflowResult {
289→  const result: AssessWorkflowResult = {
290→    phases: [],
291→    qualityLoop: false,
292→    issueNumbers: [],
293→  };
294→
295→  // Extract action from "→ ACTION — reason" line
296→  const actionMatch = body.match(
297→    /→\s*(PROCEED|CLOSE|MERGE|REWRITE|CLARIFY|PARK)\s*[—-]/,
298→  );
299→  if (actionMatch) {
300→    result.action = actionMatch[1] as AssessAction;
301→  }
302→
303→  // Extract issue numbers from header (both old and new formats)
304→  const headerMatch = body.match(
305→    /## (?:Assess|Solve) (?:Workflow for Issues?|Analysis)(?::\s*|\s+for\s+)([^\n]+)/i,
306→  );
307→  if (headerMatch) {
308→    const numberMatches = headerMatch[1].matchAll(ISSUE_NUMBER_PATTERN);
309→    for (const match of numberMatches) {
310→      const num = parseInt(match[1], 10);
311→      if (!isNaN(num) && !result.issueNumbers.includes(num)) {
312→        result.issueNumbers.push(num);
313→      }
314→    }
315→  }
316→
317→  // Try HTML comment markers first (most reliable, machine-readable)
318→  const markers = parseAssessMarkers(body);
319→
320→  // Action from markers overrides inline detection
321→  if (markers.action) {
322→    result.action = markers.action;
323→  }
324→
325→  if (markers.phases && markers.phases.length > 0) {
326→    result.phases = markers.phases as Phase[];
327→    result.workflowString = markers.phases.join(" → ");
328→  }
329→
330→  if (markers.qualityLoop !== undefined) {
331→    result.qualityLoop = markers.qualityLoop;
332→  }
333→
334→  // If we got phases from markers, we're done with phase detection
335→  if (result.phases.length > 0) {
336→    return result;
337→  }
338→
339→  // Find workflow lines (e.g., "/spec 152" or "spec → exec → qa")
340→  const lines = body.split("\n");
341→
342→  // First pass: look for arrow notation (most reliable)
343→  for (const line of lines) {
344→    if (line.includes("→") || line.includes("->")) {
345→      const phases = parseWorkflowString(line);
346→      if (phases.length > 0) {
347→        result.phases = phases;
348→        result.workflowString = line.trim();
349→        break;
350→      }
351→    }
352→  }
353→
354→  // Second pass: if no arrow notation found, collect phases from multiple lines
355→  if (result.phases.length === 0) {
356→    const collectedPhases: Phase[] = [];
357→
358→    for (const line of lines) {
359→      if (
360→        line.includes("/spec") ||
361→        line.includes("/exec") ||
362→        line.includes("/test") ||
363→        line.includes("/qa")
364→      ) {
365→        const linePhases = parseWorkflowString(line);
366→        for (const phase of linePhases) {
367→          if (!collectedPhases.includes(phase)) {
368→            collectedPhases.push(phase);
369→          }
370→        }
371→      }
372→    }
373→
374→    if (collectedPhases.length > 0) {
375→      result.phases = collectedPhases;
376→      result.workflowString = collectedPhases.map((p) => `/${p}`).join(" → ");
377→    }
378→  }
379→
380→  // If no phases found from lines, try full body
381→  if (result.phases.length === 0) {
382→    result.phases = parseWorkflowString(body);
383→  }
384→
385→  // Check for quality loop recommendation (if not already set by markers)
386→  if (!result.qualityLoop) {
387→    for (const pattern of QUALITY_LOOP_PATTERNS) {
388→      if (pattern.test(body)) {
389→        result.qualityLoop = true;
390→        break;
391→      }
392→    }
393→  }
394→
395→  return result;
396→}
397→
398→/**
399→ * Parse a solve comment to extract workflow information
400→ * @deprecated Use parseAssessWorkflow instead
401→ */
402→export function parseSolveWorkflow(body: string): AssessWorkflowResult {
403→  return parseAssessWorkflow(body);
404→}
405→
406→// ─── Signal Conversion ──────────────────────────────────────────────────────
407→
408→/**
409→ * Convert assess workflow result to phase signals
410→ *
411→ * Uses source 'solve' internally for backward compatibility with
412→ * the phase signal priority system.
413→ */
414→export function assessWorkflowToSignals(
415→  workflow: AssessWorkflowResult,
416→): PhaseSignal[] {
417→  const signals: PhaseSignal[] = [];
418→
419→  for (const phase of workflow.phases) {
420→    signals.push({
421→      phase,
422→      source: "solve",
423→      confidence: "high",
424→      reason: `Recommended by /assess command: ${workflow.workflowString || phase}`,
425→    });
426→  }
427→
428→  if (workflow.qualityLoop) {
429→    signals.push({
430→      phase: "quality-loop",
431→      source: "solve",
432→      confidence: "high",
433→      reason: "Quality loop recommended by /assess command",
434→    });
435→  }
436→
437→  return signals;
438→}
439→
440→/**
441→ * Convert solve workflow result to phase signals
442→ * @deprecated Use assessWorkflowToSignals instead
443→ */
444→export function solveWorkflowToSignals(
445→  workflow: AssessWorkflowResult,
446→): PhaseSignal[] {
447→  return assessWorkflowToSignals(workflow);
448→}
449→
450→// ─── Utility Functions ──────────────────────────────────────────────────────
451→
452→/**
453→ * Check if assess/solve comment covers the current issue
454→ */
455→export function assessCoversIssue(
456→  workflow: AssessWorkflowResult,
457→  issueNumber: number,
458→): boolean {
459→  return workflow.issueNumbers.includes(issueNumber);
460→}
461→
462→/**
463→ * Check if solve comment covers the current issue
464→ * @deprecated Use assessCoversIssue instead
465→ */
466→export function solveCoversIssue(
467→  workflow: AssessWorkflowResult,
468→  issueNumber: number,
469→): boolean {
470→  return assessCoversIssue(workflow, issueNumber);
471→}
