export type {
  ContentSignal,
  ContentAnalysisResult,
} from "./lib/content-analyzer.js";

export {
  mergePhaseSignals,
  signalFromLabel,
  signalsFromLabels,
  formatMergedPhases,
  SIGNAL_PRIORITY,
} from "./lib/phase-signal.js";
export type {
  SignalSource,
  SignalConfidence,
  PhaseSignal,
  MergedPhaseResult,
} from "./lib/phase-signal.js";

// Assess comment parser exports (unified from solve + assess)
export {
  isAssessComment,
  findAssessComment,
  parseAssessMarkers,
  parseAssessWorkflow,
  assessWorkflowToSignals,
  assessCoversIssue,
  // Backward-compatible aliases (deprecated)
  isSolveComment,
  findSolveComment,
  parseSolveMarkers,
  parseSolveWorkflow,
  solveWorkflowToSignals,
  solveCoversIssue,
} from "./lib/assess-comment-parser.js";
export type {
  AssessWorkflowResult,
  AssessMarkers,
  AssessAction,
  // Backward-compatible type aliases
  SolveWorkflowResult,
  SolveMarkers,
  IssueComment,
} from "./lib/assess-comment-parser.js";

