 52→  source: SignalSource;
 53→  /** Confidence level of the signal */
 54→  confidence: SignalConfidence;
 55→  /** Human-readable reason for this signal */
 56→  reason?: string;
 57→  /** The pattern or keyword that matched (for content signals) */
 58→  match?: string;
 59→}
 60→
 61→/**
 62→ * Result of merging phase signals
 63→ */
 64→export interface MergedPhaseResult {
 65→  /** Unique phases to include in workflow */
 66→  phases: Phase[];
 67→  /** Whether quality loop should be enabled */
 68→  qualityLoop: boolean;
 69→  /** Map of phase to the signal that contributed it */
 70→  phaseSignals: Map<Phase | "quality-loop", PhaseSignal>;
