import { registerRun, unregisterRun } from "../run-registry.js";

/** Maximum total response size in bytes (64 KB) */
const MAX_RESPONSE_SIZE = 64 * 1024;

/** Maximum raw output size before truncation */
const MAX_RAW_OUTPUT = 2000;

